class AdvancedSwal {
  constructor(defaults = {}) {
    this.defaults = defaults;
    this.activeModal = null;
    this.toastQueue = [];
    this.toastActive = false;
  }

  fire(options = {}) {
    const opts = { ...this.defaults, ...options };
    if (opts.type && !opts.icon) opts.icon = opts.type;
    const btnStyling = opts.buttonsStyling !== false;
    return opts.toast ? this._enqueueToast(opts) : this._showModal(opts, btnStyling);
  }

  _showModal(opts, btnStyling = true) {
    return new Promise((resolve) => {
      if (this.activeModal) this._closeModal();

      const backdrop = document.createElement('div');
      backdrop.className = 'advSwal-backdrop';

      const modal = document.createElement('div');
      modal.className = 'advSwal-modal';

      const iconMap = {
        success: '✅', error: '❌', warning: '⚠️', info: 'ℹ️', question: '❓'
      };

      const iconWrapper = document.createElement('div');
      iconWrapper.className = 'advSwal-icon';
      modal.appendChild(iconWrapper);

      const fallbackToIcon = () => {
        if (opts.customIcon) {
          if (opts.customIcon.endsWith('.svg')) {
            fetch(opts.customIcon).then(r => r.text()).then(svg => {
              iconWrapper.innerHTML = svg;
            }).catch(() => {
              const img = document.createElement('img');
              img.src = opts.customIcon;
              img.style.maxWidth = '100px';
              iconWrapper.appendChild(img);
            });
          } else {
            const img = document.createElement('img');
            img.src = opts.customIcon;
            img.style.maxWidth = '100px';
            img.style.maxHeight = '100px';
            iconWrapper.appendChild(img);
          }
        } else if (opts.icon && iconMap[opts.icon]) {
          iconWrapper.textContent = iconMap[opts.icon];
        }
      };

      if (opts.lottie && opts.lottie.path) {
        const tryLottie = () => {
          if (window.lottie) {
            lottie.loadAnimation({
              container: iconWrapper,
              renderer: 'svg',
              loop: true,
              autoplay: true,
              path: opts.lottie.path
            });
          } else {
            fallbackToIcon();
          }
        };
        if (window.lottie) {
          tryLottie();
        } else {
          const script = document.createElement('script');
          script.src = 'https://cdnjs.cloudflare.com/ajax/libs/lottie-web/5.9.6/lottie.min.js';
          script.onload = tryLottie;
          script.onerror = fallbackToIcon;
          document.head.appendChild(script);
        }
      } else {
        fallbackToIcon();
      }

      if (opts.showCloseButton) {
        const closeBtn = document.createElement('button');
        closeBtn.innerHTML = '&times;';
        closeBtn.style.cssText = 'position:absolute;top:10px;right:15px;background:none;border:none;font-size:20px;cursor:pointer;';
        closeBtn.onclick = () => {
          clearTimeout(timerId);
          this._closeModal();
          resolve({ isDismissed: true, value: false });
        };
        modal.appendChild(closeBtn);
      }

      if (opts.title) {
        const title = document.createElement('div');
        title.className = 'advSwal-title';
        title.textContent = opts.title;
        modal.appendChild(title);
      }

      if (opts.text) {
        const text = document.createElement('div');
        text.className = 'advSwal-text';
        text.textContent = opts.text;
        modal.appendChild(text);
      }

      const buttonWrap = document.createElement('div');
      buttonWrap.className = 'advSwal-buttons';

      const confirmBtn = document.createElement('button');
      confirmBtn.textContent = opts.confirmButtonText || 'OK';
      confirmBtn.className = btnStyling ? 'advSwal-btn advSwal-btn-confirm' : (opts.confirmButtonClass || '');
      confirmBtn.onclick = () => {
        clearTimeout(timerId);
        this._closeModal();
        resolve({ isConfirmed: true, value: true });
      };
      buttonWrap.appendChild(confirmBtn);

      if (opts.showCancelButton) {
        const cancelBtn = document.createElement('button');
        cancelBtn.textContent = opts.cancelButtonText || 'Cancel';
        cancelBtn.className = btnStyling ? 'advSwal-btn advSwal-btn-cancel' : (opts.cancelButtonClass || '');
        cancelBtn.onclick = () => {
          clearTimeout(timerId);
          this._closeModal();
          resolve({ isDismissed: true, value: false });
        };
        buttonWrap.appendChild(cancelBtn);
      }

      modal.appendChild(buttonWrap);
      backdrop.appendChild(modal);
      document.body.appendChild(backdrop);
      this.activeModal = backdrop;

      document.onkeydown = (e) => {
        if (e.key === 'Escape') {
          clearTimeout(timerId);
          this._closeModal();
          resolve({ isDismissed: true, value: false });
        }
      };

      if (opts.allowOutsideClick) {
        backdrop.addEventListener('click', (e) => {
          if (e.target === backdrop) {
            clearTimeout(timerId);
            this._closeModal();
            resolve({ isDismissed: true, value: false });
          }
        });
      }

      let timerId = null;
      if (opts.timer && typeof opts.timer === "number") {
        const timerBar = document.createElement('div');
        timerBar.className = "advSwal-timer-bar";
        timerBar.style.animation = `countdown ${opts.timer}ms linear forwards`;
        modal.appendChild(timerBar);

        timerId = setTimeout(() => {
          this._closeModal();
          resolve({ isDismissed: true, value: false, reason: "timer" });
        }, opts.timer);

        modal.onmouseenter = () => {
          clearTimeout(timerId);
          timerBar.style.animationPlayState = "paused";
        };
        modal.onmouseleave = () => {
          timerBar.style.animationPlayState = "running";
          timerId = setTimeout(() => {
            this._closeModal();
            resolve({ isDismissed: true, value: false, reason: "timer" });
          }, opts.timer);
        };
      }
    });
  }

  _enqueueToast(opts) {
    return new Promise((resolve) => {
      this.toastQueue.push(() => this._showToast(opts).then(resolve));
      this._processToastQueue();
    });
  }

  _processToastQueue() {
    if (this.toastActive || this.toastQueue.length === 0) return;
    this.toastActive = true;
    const nextToast = this.toastQueue.shift();
    nextToast().finally(() => {
      this.toastActive = false;
      setTimeout(() => this._processToastQueue(), 200);
    });
  }

  _showToast(opts) {
    return new Promise((resolve) => {
      const iconMap = {
        success: '✅', error: '❌', warning: '⚠️', info: 'ℹ️', question: '❓'
      };

      const toast = document.createElement('div');
      toast.className = 'advSwal-toast';
      const pos = (opts.position || 'top-end').split('-');
      toast.style[pos[0]] = '20px';
      toast.style[pos[1]] = '20px';
      toast.style.position = "fixed";
      toast.style.pointerEvents = "auto";

      if (opts.icon && iconMap[opts.icon]) {
        const icon = document.createElement('span');
        icon.className = 'advSwal-icon';
        icon.textContent = iconMap[opts.icon];
        toast.appendChild(icon);
      }

      const content = document.createElement('div');
      content.textContent = opts.title || opts.text || '';
      toast.appendChild(content);

      if (opts.showCloseButton) {
        const closeBtn = document.createElement('button');
        closeBtn.className = 'advSwal-toast-close';
        closeBtn.innerHTML = '&times;';
        closeBtn.onclick = () => {
          clearTimeout(timerId);
          toast.remove();
          resolve({ isDismissed: true });
        };
        toast.appendChild(closeBtn);
      }

      let timerId;
      if (opts.timer) {
        const timerBar = document.createElement('div');
        timerBar.className = 'advSwal-toast-timer-bar';
        timerBar.style.animation = `countdown ${opts.timer}ms linear forwards`;
        toast.appendChild(timerBar);

        timerId = setTimeout(() => {
          toast.remove();
          resolve({ isDismissed: true });
        }, opts.timer);

        toast.onmouseenter = () => {
          clearTimeout(timerId);
          timerBar.style.animationPlayState = "paused";
        };
        toast.onmouseleave = () => {
          timerBar.style.animationPlayState = "running";
          timerId = setTimeout(() => {
            toast.remove();
            resolve({ isDismissed: true });
          }, opts.timer);
        };
      }

      document.body.appendChild(toast);
    });
  }

  _closeModal() {
    if (this.activeModal) {
      document.body.removeChild(this.activeModal);
      this.activeModal = null;
      document.onkeydown = null;
    }
  }

  queue(steps) {
    const results = [];
    const next = (i) => {
      if (i >= steps.length) return Promise.resolve(results);
      return this.fire(steps[i]).then(result => {
        results.push(result);
        return next(i + 1);
      });
    };
    return next(0);
  }

  mixin(config) {
    return new AdvancedSwal({ ...this.defaults, ...config });
  }
}

const Swal = new AdvancedSwal();